    <style>
        *{font-family:'Switzer',system-ui,sans-serif;-webkit-tap-highlight-color:transparent;box-sizing:border-box}
        h1,h2,h3,h4,.font-display{font-family:'Clash Display',system-ui,sans-serif}
        code,.font-mono{font-family:'JetBrains Mono',monospace}
        body{background:#f8fafc;color:#0f172a;overflow-x:hidden}
        ::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:#cbd5e1;border-radius:99px}
        .scrollbar-hide::-webkit-scrollbar{display:none}.scrollbar-hide{-ms-overflow-style:none;scrollbar-width:none}
        select option{background:#fff;color:#0f172a}

        /* ═══ ANIMATIONS — GenZ/GenAlpha level ═══ */
        @keyframes fadeUp{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        @keyframes slideRight{from{opacity:0;transform:translateX(24px)}to{opacity:1;transform:translateX(0)}}
        @keyframes slideLeft{from{opacity:0;transform:translateX(-24px)}to{opacity:1;transform:translateX(0)}}
        @keyframes slideDown{from{opacity:0;transform:translateY(-20px)}to{opacity:1;transform:translateY(0)}}
        @keyframes stagger{from{opacity:0;transform:translateY(14px) scale(.98)}to{opacity:1;transform:translateY(0) scale(1)}}
        @keyframes scaleIn{from{opacity:0;transform:scale(.92)}to{opacity:1;transform:scale(1)}}
        @keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-12px)}}
        @keyframes floatSlow{0%,100%{transform:translateY(0) rotate(0deg)}50%{transform:translateY(-8px) rotate(2deg)}}
        @keyframes blob{0%,100%{border-radius:60% 40% 30% 70%/60% 30% 70% 40%}50%{border-radius:30% 60% 70% 40%/50% 60% 30% 60%}}
        @keyframes spin-dot{to{transform:rotate(360deg)}}
        @keyframes pulse-glow{0%,100%{box-shadow:0 0 6px rgba(37,99,235,0.2)}50%{box-shadow:0 0 18px rgba(37,99,235,0.45)}}
        @keyframes shimmer{0%{background-position:-200% 0}100%{background-position:200% 0}}
        @keyframes gradient-shift{0%{background-position:0% 50%}50%{background-position:100% 50%}100%{background-position:0% 50%}}
        @keyframes toastIn{from{opacity:0;transform:translate(-50%,20px) scale(.92)}to{opacity:1;transform:translate(-50%,0) scale(1)}}
        @keyframes toastOut{to{opacity:0;transform:translate(-50%,-10px) scale(.92)}}
        @keyframes wiggle{0%,100%{transform:rotate(0deg)}25%{transform:rotate(-3deg)}75%{transform:rotate(3deg)}}
        @keyframes typewriter{from{width:0}to{width:100%}}
        @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
        @keyframes morphBg{0%{background-position:0% 0%}50%{background-position:100% 100%}100%{background-position:0% 0%}}
        @keyframes otpShake{0%,100%{transform:translateX(0)}20%,60%{transform:translateX(-6px)}40%,80%{transform:translateX(6px)}}
        @keyframes countdownPulse{0%,100%{opacity:1}50%{opacity:.5}}
        @keyframes ripple{0%{transform:scale(1);opacity:1}100%{transform:scale(1.5);opacity:0}}

        /* ═══ ANIMATION CLASSES ═══ */
        .anim-fade-up{animation:fadeUp .6s cubic-bezier(.16,1,.3,1) both}
        .anim-fade-in{animation:fadeIn .5s ease both}
        .anim-scale-in{animation:scaleIn .5s cubic-bezier(.16,1,.3,1) both}
        .anim-slide-right{animation:slideRight .5s cubic-bezier(.16,1,.3,1) both}
        .anim-slide-left{animation:slideLeft .5s cubic-bezier(.16,1,.3,1) both}
        .anim-float{animation:float 5s ease-in-out infinite}
        .anim-float-slow{animation:floatSlow 7s ease-in-out infinite}
        .anim-wiggle:hover{animation:wiggle .4s ease}
        .anim-gradient{background-size:200% 200%;animation:gradient-shift 4s ease infinite}

        /* ═══ SCROLL REVEAL — Intersection Observer driven ═══ */
        .scroll-reveal{opacity:0;transform:translateY(35px) scale(.98);transition:all .8s cubic-bezier(.16,1,.3,1)}
        .scroll-reveal.revealed{opacity:1;transform:translateY(0) scale(1)}
        .scroll-reveal-left{opacity:0;transform:translateX(-40px);transition:all .8s cubic-bezier(.16,1,.3,1)}
        .scroll-reveal-left.revealed{opacity:1;transform:translateX(0)}
        .scroll-reveal-right{opacity:0;transform:translateX(40px);transition:all .8s cubic-bezier(.16,1,.3,1)}
        .scroll-reveal-right.revealed{opacity:1;transform:translateX(0)}
        .scroll-reveal-scale{opacity:0;transform:scale(.88);transition:all .7s cubic-bezier(.16,1,.3,1)}
        .scroll-reveal-scale.revealed{opacity:1;transform:scale(1)}

        /* ═══ COMPONENTS ═══ */
        .card{background:#fff;border:1px solid #e2e8f0;border-radius:16px;transition:all .3s cubic-bezier(.16,1,.3,1)}
        .card:hover{border-color:#bfdbfe;box-shadow:0 8px 32px rgba(37,99,235,0.07);transform:translateY(-2px)}
        .card-flat{background:#f1f5f9;border:1px solid #e2e8f0;border-radius:14px}
        .glass{background:rgba(255,255,255,0.72);backdrop-filter:blur(24px) saturate(180%);-webkit-backdrop-filter:blur(24px) saturate(180%);border:1px solid rgba(255,255,255,0.25)}
        .progress-bar{transition:width 1.5s cubic-bezier(.16,1,.3,1)}
        .shimmer{background:linear-gradient(90deg,transparent,rgba(255,255,255,0.4),transparent);background-size:200% 100%;animation:shimmer 2s infinite}

        /* ═══ TABS ═══ */
        .tab-active{background:rgba(37,99,235,0.08);border-color:rgba(37,99,235,0.2);color:#2563eb}
        .tab-active .tab-icon{background:rgba(37,99,235,0.12);color:#2563eb}

        /* ═══ FORM ELEMENTS ═══ */
        input,select,textarea{background:#f1f5f9;border:1px solid #e2e8f0;border-radius:12px;color:#0f172a;transition:all .25s cubic-bezier(.16,1,.3,1)}
        input:focus,select:focus,textarea:focus{outline:none;border-color:#3b82f6!important;box-shadow:0 0 0 4px rgba(59,130,246,0.1);transform:scale(1.005)}
        input::placeholder,textarea::placeholder{color:#94a3b8}

        /* ═══ BUTTONS — with ripple effect ═══ */
        .btn{transition:all .25s cubic-bezier(.16,1,.3,1);position:relative;border-radius:12px;font-weight:600;cursor:pointer;overflow:hidden}
        .btn:active{transform:scale(.96)}
        .btn::after{content:'';position:absolute;inset:0;background:radial-gradient(circle at var(--x,50%) var(--y,50%),rgba(255,255,255,0.3) 0%,transparent 60%);opacity:0;transition:opacity .3s}
        .btn:active::after{opacity:1}
        .btn-primary{background:#2563eb;color:white;box-shadow:0 2px 16px rgba(37,99,235,0.22)}
        .btn-primary:hover{background:#1d4ed8;box-shadow:0 6px 24px rgba(37,99,235,0.32);transform:translateY(-2px)}
        .btn-ghost{background:#f1f5f9;border:1px solid #e2e8f0;color:#334155}
        .btn-ghost:hover{background:#e2e8f0;border-color:#cbd5e1;transform:translateY(-1px)}
        .btn-success{background:#059669;color:white;box-shadow:0 2px 12px rgba(5,150,105,0.2)}
        .btn-success:hover{background:#047857;transform:translateY(-1px)}
        .btn-amber{background:#d97706;color:white;box-shadow:0 2px 12px rgba(217,119,6,0.2)}
        .btn-amber:hover{background:#b45309;transform:translateY(-1px)}
        .btn-violet{background:#7c3aed;color:white;box-shadow:0 2px 12px rgba(124,58,237,0.2)}
        .btn-violet:hover{background:#6d28d9;transform:translateY(-1px)}

        /* ═══ BADGES ═══ */
        .badge-new{background:#eff6ff;color:#2563eb;border:1px solid #bfdbfe}
        .badge-contacted{background:#fffbeb;color:#b45309;border:1px solid #fde68a}
        .badge-followup{background:#fff7ed;color:#c2410c;border:1px solid #fed7aa}
        .badge-negotiating{background:#f5f3ff;color:#6d28d9;border:1px solid #ddd6fe}
        .badge-closed{background:#ecfdf5;color:#047857;border:1px solid #a7f3d0}
        .badge-lost{background:#fef2f2;color:#dc2626;border:1px solid #fecaca}
        .badge-hot{background:#fef2f2;color:#dc2626;border:1px solid #fecaca}
        .badge-warm{background:#fffbeb;color:#b45309;border:1px solid #fde68a}
        .badge-cold{background:#eff6ff;color:#2563eb;border:1px solid #bfdbfe}

        /* ═══ SPECIAL UI ═══ */
        .onboard-step{display:none}.onboard-step.active{display:block;animation:fadeUp .5s cubic-bezier(.16,1,.3,1) both}
        .ob-progress{transition:width .5s cubic-bezier(.16,1,.3,1)}
        .toggle-track{width:42px;height:24px;border-radius:99px;background:#cbd5e1;cursor:pointer;transition:background .3s;position:relative}
        .toggle-track.active{background:#2563eb}
        .toggle-knob{width:20px;height:20px;border-radius:50%;background:white;position:absolute;top:2px;left:2px;transition:transform .3s cubic-bezier(.16,1,.3,1);box-shadow:0 1px 4px rgba(0,0,0,.15)}
        .toggle-track.active .toggle-knob{transform:translateX(18px)}
        .maps-frame{border-radius:16px;overflow:hidden;border:1px solid #e2e8f0}
        .notif-dot{width:7px;height:7px;background:#2563eb;border-radius:50%;position:absolute;top:-1px;right:-1px;animation:pulse-glow 2s ease-in-out infinite}
        .spinner{width:16px;height:16px;border:2px solid rgba(37,99,235,0.15);border-top-color:#2563eb;border-radius:50%;animation:spin-dot .6s linear infinite}

        /* ═══ LANDING VISUALS ═══ */
        .landing-grid{background-image:linear-gradient(rgba(37,99,235,0.02) 1px,transparent 1px),linear-gradient(90deg,rgba(37,99,235,0.02) 1px,transparent 1px);background-size:64px 64px}
        .hero-blob{position:absolute;border-radius:50%;filter:blur(100px);opacity:0.12;animation:blob 16s ease-in-out infinite;pointer-events:none}
        .hero-grain{position:absolute;inset:0;opacity:0.03;pointer-events:none;background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E")}
        .pricing-glow{box-shadow:0 0 50px rgba(37,99,235,0.08),0 20px 60px rgba(37,99,235,0.05)}
        .stat-card{background:linear-gradient(135deg,rgba(255,255,255,0.9),rgba(255,255,255,0.6));backdrop-filter:blur(10px);border:1px solid rgba(37,99,235,0.06);border-radius:16px;transition:all .35s cubic-bezier(.16,1,.3,1)}
        .stat-card:hover{transform:translateY(-3px);box-shadow:0 12px 36px rgba(0,0,0,0.05)}
        .auth-mesh{background-image:radial-gradient(at 20% 80%,rgba(37,99,235,0.06) 0%,transparent 50%),radial-gradient(at 80% 20%,rgba(6,182,212,0.06) 0%,transparent 50%),radial-gradient(at 50% 50%,rgba(16,185,129,0.04) 0%,transparent 50%)}

        /* ═══ OTP INPUTS ═══ */
        .otp-input{width:48px;height:56px;text-align:center;font-size:22px;font-weight:800;font-family:'Clash Display',system-ui,sans-serif;letter-spacing:0;border-radius:14px;caret-color:#2563eb;transition:all .25s cubic-bezier(.16,1,.3,1)}
        .otp-input:focus{border-color:#2563eb;box-shadow:0 0 0 4px rgba(37,99,235,0.12);transform:scale(1.06)}
        .otp-input.filled{border-color:#2563eb;background:#eff6ff}
        .otp-shake{animation:otpShake .4s ease}
        .countdown-pulse{animation:countdownPulse 1s ease-in-out infinite}

        /* ═══ TOAST ═══ */
        .toast{position:fixed;bottom:24px;left:50%;transform:translate(-50%,0);z-index:9999;padding:12px 24px;border-radius:14px;font-size:13px;font-weight:600;color:#fff;display:flex;align-items:center;gap:10px;animation:toastIn .45s cubic-bezier(.16,1,.3,1) both;box-shadow:0 12px 48px rgba(0,0,0,0.18),0 0 0 1px rgba(255,255,255,0.1) inset;max-width:90vw}
        .toast-success{background:linear-gradient(135deg,#059669,#047857)}
        .toast-error{background:linear-gradient(135deg,#dc2626,#b91c1c)}
        .toast-info{background:linear-gradient(135deg,#2563eb,#1d4ed8)}
        .toast-warning{background:linear-gradient(135deg,#d97706,#b45309)}
        .toast-exit{animation:toastOut .3s ease forwards}

        /* ═══ FLOATING WHATSAPP ═══ */
        .wa-float{position:fixed;bottom:24px;right:24px;z-index:80;width:56px;height:56px;border-radius:50%;background:#25D366;color:white;display:flex;align-items:center;justify-content:center;font-size:28px;box-shadow:0 4px 20px rgba(37,211,102,0.35);transition:all .3s cubic-bezier(.16,1,.3,1);cursor:pointer}
        .wa-float:hover{transform:scale(1.1) translateY(-3px);box-shadow:0 8px 32px rgba(37,211,102,0.45)}
        .wa-float:active{transform:scale(.95)}
        .wa-pulse{position:absolute;inset:-4px;border-radius:50%;border:2px solid #25D366;animation:ripple 2s ease-out infinite;pointer-events:none}

        /* ═══ RESPONSIVE OVERRIDES ═══ */
        @media(max-width:480px){
            .mobile-stack{flex-direction:column}
            .mobile-full{width:100%}
            .mobile-hide{display:none}
            .otp-input{width:40px;height:46px;font-size:17px}
            .wa-float{width:50px;height:50px;font-size:24px;bottom:16px;right:16px}
            .toast{bottom:80px;font-size:12px;padding:10px 18px}
            h1{font-size:1.875rem!important;line-height:1.1!important}
            h2{font-size:1.5rem!important}
            .card{border-radius:14px}
            .stat-card{border-radius:12px}
        }
        @media(min-width:481px) and (max-width:768px){
            h1{font-size:2.5rem!important}
        }
        @media(min-width:1537px){
            body{font-size:17px}
            .max-w-7xl{max-width:1400px}
        }
    </style>
</head><body class="min-h-screen">

<!-- ═══ FLOATING WHATSAPP ═══ -->
<a href="https://wa.me/YOUR_WHATSAPP_NUMBER?text=Hi%20GigBase!%20I%20need%20help%20with%20the%20platform." target="_blank" class="wa-float" aria-label="Chat on WhatsApp" title="Chat with us on WhatsApp">
    <div class="wa-pulse"></div>
    <i class="fa-brands fa-whatsapp"></i>
</a>

<!-- ═══ AUTH SCREEN ═══ -->
<div id="auth-screen" class="fixed inset-0 z-[200] bg-[#f8fafc] hidden auth-mesh">
    <div class="min-h-screen flex flex-col items-center justify-center p-4">
        <div class="max-w-sm w-full">
            <div id="auth-email-step" class="text-center">
                <div class="w-20 h-20 rounded-2xl bg-gradient-to-br from-brand-600 to-cyan-500 flex items-center justify-center mx-auto mb-6 shadow-xl shadow-brand-500/20 anim-float-slow"><img src="assets/gigbase-icon-64.png" alt="GigBase" class="w-12 h-12 rounded-lg"></div>
                <h1 class="text-3xl sm:text-4xl font-black font-display bg-gradient-to-r from-brand-600 to-cyan-500 bg-clip-text text-transparent">GigBase</h1>
                <p class="text-ink-500 mt-2 text-sm">Log in or sign up with your email</p>
                <div class="mt-8 space-y-4">
                    <div class="relative"><i class="fa-solid fa-envelope absolute left-4 top-1/2 -translate-y-1/2 text-ink-400 text-sm"></i><input id="auth-email" type="email" placeholder="your@email.com" class="w-full pl-11 pr-4 py-4 text-sm font-medium" autocomplete="email" autofocus></div>
                    <p id="auth-email-error" class="text-[11px] text-red-500 text-left hidden"></p>
                    <button onclick="sendOTP()" id="auth-send-btn" class="btn btn-primary w-full py-4 text-sm flex items-center justify-center gap-2"><i class="fa-solid fa-paper-plane"></i><span>Send Login Code</span></button>
                </div>
                <div class="mt-8 flex items-center gap-3"><div class="flex-1 h-px bg-ink-200"></div><span class="text-[9px] text-ink-400 uppercase tracking-[0.2em] font-bold">No password needed</span><div class="flex-1 h-px bg-ink-200"></div></div>
                <div class="mt-6 flex items-center justify-center gap-6 text-[10px] text-ink-400"><div class="flex items-center gap-1.5"><i class="fa-solid fa-shield-halved text-emerald-500"></i> Secure OTP</div><div class="flex items-center gap-1.5"><i class="fa-solid fa-clock text-brand-500"></i> 60-second login</div><div class="flex items-center gap-1.5"><i class="fa-solid fa-lock text-amber-500"></i> No spam</div></div>
            </div>
            <div id="auth-otp-step" class="text-center hidden">
                <div class="w-16 h-16 rounded-2xl bg-gradient-to-br from-emerald-500 to-teal-500 flex items-center justify-center mx-auto mb-5 shadow-xl shadow-emerald-500/20"><i class="fa-solid fa-key text-white text-xl"></i></div>
                <h2 class="text-2xl font-black font-display text-ink-900">Check Your Email</h2>
                <p class="text-ink-500 mt-2 text-sm">We sent a 6-digit code to</p>
                <p id="auth-sent-to" class="text-sm font-bold text-brand-600 mt-1"></p>
                <div class="mt-8 flex justify-center gap-2" id="otp-inputs">
                    <input type="text" maxlength="1" inputmode="numeric" pattern="[0-9]" class="otp-input" data-idx="0">
                    <input type="text" maxlength="1" inputmode="numeric" pattern="[0-9]" class="otp-input" data-idx="1">
                    <input type="text" maxlength="1" inputmode="numeric" pattern="[0-9]" class="otp-input" data-idx="2">
                    <div class="flex items-center"><div class="w-2 h-0.5 bg-ink-300 rounded"></div></div>
