<script>
let APP={settings:{},user:null,currentTab:'dashboard',pitchTemplates:[],selectedPitchTemplate:null,noWebsiteFilter:true,searchResults:[],authEmail:'',otpCountdown:null,
niches:[{id:'interior',label:'Interior Design',icon:'fa-couch',query:'interior designer'},{id:'clinic',label:'Clinic / Doctor',icon:'fa-stethoscope',query:'dental clinic'},{id:'coaching',label:'Coaching',icon:'fa-graduation-cap',query:'coaching class'},{id:'gym',label:'Gym / Fitness',icon:'fa-dumbbell',query:'gym'},{id:'salon',label:'Salon / Spa',icon:'fa-scissors',query:'salon'},{id:'restaurant',label:'Restaurant',icon:'fa-utensils',query:'restaurant'},{id:'real-estate',label:'Real Estate',icon:'fa-house',query:'real estate agent'},{id:'event',label:'Event Planner',icon:'fa-champagne-glasses',query:'event planner'},{id:'auto',label:'Auto / Garage',icon:'fa-car',query:'car showroom'},{id:'ecommerce',label:'Local Shop',icon:'fa-store',query:'clothing store'},{id:'photographer',label:'Photographer',icon:'fa-camera',query:'photographer'},{id:'lawyer',label:'Lawyer / CA',icon:'fa-scale-balanced',query:'lawyer'}]};
const SYM={INR:'₹',USD:'$',EUR:'€',GBP:'£'};
async function api(ep,method='GET',data=null){const o={method,headers:{'Content-Type':'application/json'}};if(data)o.body=JSON.stringify(data);try{const r=await fetch(`api/${ep}`,o);const j=await r.json();if(j.auth_required){showAuthScreen();return{error:'Session expired'};}return j;}catch(e){console.error('API:',e);return{error:e.message};}}
function debounce(fn,ms){let t;return function(...a){clearTimeout(t);t=setTimeout(()=>fn.apply(this,a),ms);};}
const debouncedLoadLeads=debounce(loadLeads,300);
function $(id){return document.getElementById(id);}
function esc(s){if(!s)return'';const d=document.createElement('div');d.textContent=s;return d.innerHTML;}
function rawText(s){if(!s)return'';const d=document.createElement('textarea');d.innerHTML=s;return d.value;}

// ═══ SCROLL REVEAL — Enhanced with multiple directions ═══
const observer=new IntersectionObserver((entries)=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('revealed');observer.unobserve(e.target);}});},{threshold:0.08,rootMargin:'0px 0px -50px 0px'});
function initScrollReveal(){document.querySelectorAll('.scroll-reveal,.scroll-reveal-left,.scroll-reveal-right,.scroll-reveal-scale').forEach(el=>observer.observe(el));}

// ═══ Active Business Score badge helper ═══
function activeScoreBadge(score,label){const c={hot:{bg:'bg-red-50',text:'text-red-700',border:'border-red-100',icon:'fa-fire'},warm:{bg:'bg-amber-50',text:'text-amber-700',border:'border-amber-100',icon:'fa-temperature-half'},cold:{bg:'bg-blue-50',text:'text-blue-600',border:'border-blue-100',icon:'fa-snowflake'}};const x=c[label]||c.cold;return`<span class="px-1.5 py-0.5 rounded-md text-[8px] font-bold ${x.bg} ${x.text} border ${x.border}"><i class="fa-solid ${x.icon} mr-0.5"></i>${score}</span>`;}

// ═══ BOOT ═══
document.addEventListener('DOMContentLoaded',async()=>{
    initNicheChips();initOTPInputs();
    const d=await api('auth.php');
    if(d.authenticated){APP.user=d.user;APP.settings=d.settings||{};hideAllScreens();if(!d.user.onboarded)showOnboarding();else showApp();}
    else{hideAllScreens();showLanding();}
    animateLandingCounters();initScrollReveal();
});
function hideAllScreens(){$('auth-screen').classList.add('hidden');$('landing-page').classList.add('hidden');$('app-shell').classList.add('hidden');$('onboarding-overlay').classList.add('hidden');}
function showAuthScreen(){hideAllScreens();$('auth-screen').classList.remove('hidden');$('auth-email-step').classList.remove('hidden');$('auth-otp-step').classList.add('hidden');$('auth-email-error').classList.add('hidden');$('auth-email').focus();}
function showLanding(){hideAllScreens();$('landing-page').classList.remove('hidden');setTimeout(initScrollReveal,100);}
function showOnboarding(){hideAllScreens();$('onboarding-overlay').classList.remove('hidden');}
function showApp(){hideAllScreens();$('app-shell').classList.remove('hidden');applySettings();switchTab('dashboard');loadSearchLimits();}

// ═══ AUTH ═══
function initOTPInputs(){const inputs=document.querySelectorAll('.otp-input');inputs.forEach((inp,i)=>{inp.addEventListener('input',e=>{const v=e.target.value.replace(/\D/g,'');e.target.value=v;if(v)e.target.classList.add('filled');else e.target.classList.remove('filled');if(v&&i<5)inputs[i+1].focus();if(i===5&&v){const full=Array.from(inputs).map(x=>x.value).join('');if(full.length===6)verifyOTP();}});inp.addEventListener('keydown',e=>{if(e.key==='Backspace'&&!e.target.value&&i>0){inputs[i-1].focus();inputs[i-1].value='';inputs[i-1].classList.remove('filled');}if(e.key==='ArrowLeft'&&i>0)inputs[i-1].focus();if(e.key==='ArrowRight'&&i<5)inputs[i+1].focus();});inp.addEventListener('paste',e=>{e.preventDefault();const paste=(e.clipboardData||window.clipboardData).getData('text').replace(/\D/g,'').slice(0,6);paste.split('').forEach((c,j)=>{if(inputs[j]){inputs[j].value=c;inputs[j].classList.add('filled');}});if(paste.length>=6){inputs[5].focus();setTimeout(verifyOTP,100);}else if(paste.length>0)inputs[Math.min(paste.length,5)].focus();});});$('auth-email')?.addEventListener('keydown',e=>{if(e.key==='Enter')sendOTP();});}
async function sendOTP(){const email=$('auth-email').value.trim().toLowerCase();const errEl=$('auth-email-error');errEl.classList.add('hidden');if(!email||!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){errEl.textContent='Enter a valid email address.';errEl.classList.remove('hidden');return;}const btn=$('auth-send-btn');btn.innerHTML='<div class="spinner"></div><span>Sending code...</span>';btn.disabled=true;const d=await fetch('api/auth.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'send_otp',email})}).then(r=>r.json()).catch(e=>({error:e.message}));btn.innerHTML='<i class="fa-solid fa-paper-plane"></i><span>Send Login Code</span>';btn.disabled=false;if(d.error){errEl.textContent=d.error;errEl.classList.remove('hidden');return;}APP.authEmail=email;$('auth-sent-to').textContent=email;$('auth-email-step').classList.add('hidden');$('auth-otp-step').classList.remove('hidden');document.querySelectorAll('.otp-input').forEach(i=>{i.value='';i.classList.remove('filled');});document.querySelector('.otp-input')?.focus();startResendCountdown();}
async function verifyOTP(){const inputs=document.querySelectorAll('.otp-input');const otp=Array.from(inputs).map(i=>i.value).join('');const errEl=$('auth-otp-error');errEl.classList.add('hidden');if(otp.length!==6){errEl.textContent='Enter all 6 digits.';errEl.classList.remove('hidden');$('otp-inputs').classList.add('otp-shake');setTimeout(()=>$('otp-inputs').classList.remove('otp-shake'),400);return;}const btn=$('auth-verify-btn');btn.innerHTML='<div class="spinner"></div><span>Verifying...</span>';btn.disabled=true;const d=await fetch('api/auth.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'verify_otp',email:APP.authEmail,otp})}).then(r=>r.json()).catch(e=>({error:e.message}));btn.innerHTML='<i class="fa-solid fa-right-to-bracket"></i><span>Verify & Login</span>';btn.disabled=false;if(d.error){errEl.textContent=d.error;errEl.classList.remove('hidden');$('otp-inputs').classList.add('otp-shake');setTimeout(()=>$('otp-inputs').classList.remove('otp-shake'),400);inputs.forEach(i=>{i.value='';i.classList.remove('filled');});inputs[0].focus();return;}APP.user=d.user;APP.settings=d.settings||{};hideAllScreens();if(d.new_user||!d.user.onboarded){showOnboarding();showToast('Welcome! Let\'s set up your account.','success');}else{showApp();showToast(`Welcome back${d.user.display_name?', '+d.user.display_name:''}!`,'success');}}
function backToEmail(){$('auth-otp-step').classList.add('hidden');$('auth-email-step').classList.remove('hidden');$('auth-email').focus();if(APP.otpCountdown)clearInterval(APP.otpCountdown);}
function startResendCountdown(){let sec=60;const btn=$('auth-resend-btn');const txt=$('auth-resend-text');const cd=$('auth-countdown');btn.disabled=true;if(APP.otpCountdown)clearInterval(APP.otpCountdown);APP.otpCountdown=setInterval(()=>{sec--;cd.textContent=sec;if(sec<=0){clearInterval(APP.otpCountdown);btn.disabled=false;txt.innerHTML='<i class="fa-solid fa-rotate-right mr-1"></i>Resend Code';}},1000);}
async function resendOTP(){const d=await fetch('api/auth.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'send_otp',email:APP.authEmail})}).then(r=>r.json()).catch(e=>({error:e.message}));if(d.error){showToast(d.error,'error');return;}showToast('New code sent!','success');startResendCountdown();document.querySelectorAll('.otp-input').forEach(i=>{i.value='';i.classList.remove('filled');});document.querySelector('.otp-input')?.focus();}
async function logoutUser(){if(!confirm('Log out of GigBase?'))return;await fetch('api/auth.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'logout'})});APP.user=null;APP.settings={};closeSettings();showLanding();showToast('Logged out.','info');}
async function requestDeleteAccount(){if(!confirm('Are you sure? This will permanently delete ALL your data.'))return;const d=await api('auth.php','POST',{action:'delete_account'});if(d.error){showToast(d.error,'error');return;}$('delete-step-1').classList.add('hidden');$('delete-step-2').classList.remove('hidden');showToast('Deletion code sent.','warning');}
async function confirmDeleteAccount(){const otp=$('delete-otp').value.trim();if(!otp||otp.length!==6){showToast('Enter the 6-digit code.','warning');return;}const btn=$('delete-confirm-btn');btn.textContent='Deleting...';btn.disabled=true;const d=await api('auth.php','POST',{action:'confirm_delete',otp});btn.textContent='Confirm';btn.disabled=false;if(d.error){showToast(d.error,'error');return;}APP.user=null;APP.settings={};closeSettings();showLanding();showToast('Account deleted.','info');}
function cancelDelete(){$('delete-step-1').classList.remove('hidden');$('delete-step-2').classList.add('hidden');$('delete-otp').value='';}

// ═══ SETTINGS ═══
function applySettings(){const s=APP.settings;$('header-brand').textContent=s.brand_name||'GigBase';$('header-tagline').textContent=s.tagline||'Hunt · Pitch · Close';document.title=`${s.brand_name||'GigBase'} — GigBase`;const p=(s.plan||'free').replace('_',' ').toUpperCase();$('plan-badge-text').textContent=p;}
function animateLandingCounters(){animateNum('landing-counter-1',2847,2000);animateNum('landing-counter-2',12340,2200);animateNum('landing-counter-3',847000,2400,'₹',true);}
function animateNum(id,target,dur,prefix='',inr=false){const el=$(id);if(!el)return;const st=performance.now();(function u(n){const p=Math.min((n-st)/dur,1);const e=1-Math.pow(1-p,3);el.textContent=prefix+(inr?Math.floor(target*e).toLocaleString('en-IN'):Math.floor(target*e).toLocaleString());if(p<1)requestAnimationFrame(u);})(st);}
function switchTab(tab){APP.currentTab=tab;document.querySelectorAll('.tab-content').forEach(e=>e.classList.add('hidden'));document.querySelectorAll('.tab-btn').forEach(b=>{b.classList.remove('tab-active');b.classList.add('text-ink-400');});const el=$(`tab-${tab}`);if(el){el.classList.remove('hidden');el.classList.add('anim-fade-in');}const btn=document.querySelector(`[data-tab="${tab}"]`);if(btn){btn.classList.add('tab-active');btn.classList.remove('text-ink-400');}if(tab==='dashboard')loadDashboard();if(tab==='pipeline')loadLeads();if(tab==='revenue')loadRevenue();if(tab==='pitch')loadPitchTemplates();if(tab==='playbook')loadPlaybook();if(tab==='hunt')loadSearchLimits();if(tab==='portfolio')loadPortfolio();}

// Onboarding
function nextOnboardStep(s){document.querySelectorAll('.onboard-step').forEach(e=>e.classList.remove('active'));document.querySelector(`[data-step="${s}"]`).classList.add('active');$('ob-progress-bar').style.width=`${(s/3)*100}%`;}
function addGoalRow(){const l=$('ob-goals-list');if(l.children.length>=5)return;const r=document.createElement('div');r.className='flex gap-2 items-center ob-goal-row anim-fade-up';r.innerHTML=`<input type="text" placeholder="Goal name" class="flex-1 px-3 py-2.5 text-sm"><input type="number" placeholder="Amount" class="w-24 sm:w-28 px-3 py-2.5 text-sm"><button onclick="this.parentElement.remove()" class="text-red-400 text-xs p-1"><i class="fa-solid fa-xmark"></i></button>`;l.appendChild(r);}
function addPortfolioRow(){const l=$('ob-portfolio-list');if(l.children.length>=5)return;const r=document.createElement('div');r.className='flex gap-2 items-center ob-portfolio-row anim-fade-up';r.innerHTML=`<input type="text" placeholder="Label" class="w-28 sm:w-36 px-3 py-2.5 text-sm"><input type="url" placeholder="https://..." class="flex-1 px-3 py-2.5 text-sm"><button onclick="this.parentElement.remove()" class="text-red-400 text-xs p-1"><i class="fa-solid fa-xmark"></i></button>`;l.appendChild(r);}
async function completeOnboarding(){const goals=[],pl=[];document.querySelectorAll('.ob-goal-row').forEach(r=>{const i=r.querySelectorAll('input');if(i[0].value&&i[1].value){const n=i[0].value,e=n.match(/^(\p{Emoji})/u)?.[1]||'🎯';goals.push({name:n.replace(/^(\p{Emoji})\s*/u,''),emoji:e,target_amount:i[1].value});}});document.querySelectorAll('.ob-portfolio-row').forEach(r=>{const i=r.querySelectorAll('input');if(i[1].value)pl.push({label:i[0].value,url:i[1].value});});await api('settings.php','POST',{owner_name:$('ob-name').value,brand_name:$('ob-brand').value,tagline:$('ob-tagline').value,currency:$('ob-currency').value,revenue_target:$('ob-target').value,target_deadline:$('ob-deadline').value,whatsapp_country_code:$('ob-wacode').value,portfolio_links:pl,goals,onboarded:'1'});const d=await api('auth.php');if(d.authenticated){APP.user=d.user;APP.settings=d.settings||{};}showApp();showToast('Welcome to GigBase!','success');}
async function skipToApp(){await api('settings.php','POST',{onboarded:'1'});const d=await api('auth.php');if(d.authenticated){APP.user=d.user;APP.settings=d.settings||{};}showApp();}
function openSettings(){const s=APP.settings;$('s-name').value=s.owner_name||'';$('s-brand').value=s.brand_name||'';$('s-tagline').value=s.tagline||'';$('s-currency').value=s.currency||'INR';$('s-wacode').value=s.whatsapp_country_code||'91';$('s-target').value=s.revenue_target||'550000';$('s-deadline').value=s.target_deadline||'2027-05-01';$('s-avg-inr').value=s.avg_deal_size_inr||'15000';$('s-avg-usd').value=s.avg_deal_size_usd||'350';$('s-rate').value=s.usd_to_inr_rate||'85';$('s-plan-badge').innerHTML=`<i class="fa-solid fa-crown mr-1"></i>`+(s.plan||'free').replace('_',' ').toUpperCase();$('s-email').textContent=APP.user?.email||s.email||'';cancelDelete();let lk=[];try{lk=JSON.parse(s.portfolio_links||'[]');}catch(e){}$('s-portfolio-list').innerHTML=lk.map(l=>`<div class="flex gap-2 items-center s-portfolio-row"><input type="text" value="${esc(l.label||'')}" placeholder="Label" class="w-24 sm:w-32 px-3 py-2 text-[11px]"><input type="url" value="${esc(l.url||'')}" placeholder="https://..." class="flex-1 px-3 py-2 text-[11px]"><button onclick="this.parentElement.remove()" class="text-red-400 text-xs p-1"><i class="fa-solid fa-xmark"></i></button></div>`).join('');let gl=[];try{const g=s.goals;gl=Array.isArray(g)?g:JSON.parse(g||'[]');}catch(e){}$('s-goals-list').innerHTML=gl.map(g=>`<div class="flex gap-2 items-center s-goal-row"><input type="text" value="${esc((g.emoji||'🎯')+' '+(g.name||''))}" class="flex-1 px-3 py-2 text-[11px]"><input type="number" value="${g.target_amount||''}" class="w-20 sm:w-24 px-3 py-2 text-[11px]"><button onclick="this.parentElement.remove()" class="text-red-400 text-xs p-1"><i class="fa-solid fa-xmark"></i></button></div>`).join('');$('settings-modal').classList.remove('hidden');}
function closeSettings(){$('settings-modal').classList.add('hidden');}
function addSettingsPortfolioRow(){const l=$('s-portfolio-list'),r=document.createElement('div');r.className='flex gap-2 items-center s-portfolio-row anim-fade-up';r.innerHTML=`<input type="text" placeholder="Label" class="w-24 sm:w-32 px-3 py-2 text-[11px]"><input type="url" placeholder="https://..." class="flex-1 px-3 py-2 text-[11px]"><button onclick="this.parentElement.remove()" class="text-red-400 text-xs p-1"><i class="fa-solid fa-xmark"></i></button>`;l.appendChild(r);}
function addSettingsGoalRow(){const l=$('s-goals-list'),r=document.createElement('div');r.className='flex gap-2 items-center s-goal-row anim-fade-up';r.innerHTML=`<input type="text" placeholder="Goal" class="flex-1 px-3 py-2 text-[11px]"><input type="number" placeholder="Amount" class="w-20 sm:w-24 px-3 py-2 text-[11px]"><button onclick="this.parentElement.remove()" class="text-red-400 text-xs p-1"><i class="fa-solid fa-xmark"></i></button>`;l.appendChild(r);}
async function saveSettings(){const goals=[],pl=[];document.querySelectorAll('.s-goal-row').forEach(r=>{const i=r.querySelectorAll('input');if(i[0].value&&i[1].value){const n=i[0].value,e=n.match(/^(\p{Emoji})/u)?.[1]||'🎯';goals.push({name:n.replace(/^(\p{Emoji})\s*/u,''),emoji:e,target_amount:i[1].value});}});document.querySelectorAll('.s-portfolio-row').forEach(r=>{const i=r.querySelectorAll('input');if(i[1].value)pl.push({label:i[0].value,url:i[1].value});});await api('settings.php','POST',{owner_name:$('s-name').value,brand_name:$('s-brand').value,tagline:$('s-tagline').value,currency:$('s-currency').value,whatsapp_country_code:$('s-wacode').value,revenue_target:$('s-target').value,target_deadline:$('s-deadline').value,avg_deal_size_inr:$('s-avg-inr').value,avg_deal_size_usd:$('s-avg-usd').value,usd_to_inr_rate:$('s-rate').value,portfolio_links:pl,goals});const d=await api('settings.php');if(d.settings)APP.settings=d.settings;applySettings();closeSettings();if(APP.currentTab==='dashboard')loadDashboard();if(APP.currentTab==='revenue')loadRevenue();if(APP.currentTab==='playbook')loadPlaybook();showToast('Settings saved!','success');}
function showPricingFromApp(){$('pricing-modal').classList.remove('hidden');}
function closePricingModal(){$('pricing-modal').classList.add('hidden');}
async function buyExtendedPack(packType){if(!APP.user){showAuthScreen();return;}showToast('Extended packs coming soon! Payment integration in progress.','info');}

// Razorpay
async function initPayment(plan,currency='INR'){if(!APP.user){showAuthScreen();showToast('Log in first to upgrade.','info');return;}const d=await api('settings.php','POST',{action:'create_order',plan,currency});if(d.error){showToast(d.error,'error');return;}const options={key:d.key_id,amount:d.amount,currency:d.currency,name:'GigBase',description:`${plan.replace('_',' ').charAt(0).toUpperCase()+plan.replace('_',' ').slice(1)} Plan`,order_id:d.order_id,handler:async function(resp){const v=await api('settings.php','POST',{action:'verify_payment',razorpay_order_id:resp.razorpay_order_id,razorpay_payment_id:resp.razorpay_payment_id,razorpay_signature:resp.razorpay_signature,plan});if(v.success){APP.settings.plan=plan;showToast(`Upgraded to ${plan.replace('_',' ')}!`,'success');showApp();}else showToast('Verification failed','error');},prefill:{name:APP.settings.owner_name||'',email:APP.user?.email||''},theme:{color:'#2563eb'},modal:{ondismiss:()=>showToast('Payment cancelled','warning')}};const rzp=new Razorpay(options);rzp.open();}

// ═══ DASHBOARD ═══
async function loadDashboard(){const d=await api('stats.php');if(d.error)return;const s=APP.settings,sym=SYM[s.currency]||'₹',t=d.target;$('dash-revenue').textContent=`${sym}${t.earned.toLocaleString('en-IN')}`;$('dash-target-label').textContent=`Target: ${sym}${t.total.toLocaleString('en-IN')}`;$('dash-remaining').textContent=`${sym}${t.remaining.toLocaleString('en-IN')} to go`;$('dash-monthly').textContent=`${sym}${t.monthly_needed.toLocaleString('en-IN')}/mo needed`;$('dash-bar').style.width=`${t.pct_complete}%`;$('dash-pct').textContent=`${t.pct_complete}% · ${t.months_left}mo left`;$('header-revenue').textContent=`${sym}${t.earned.toLocaleString('en-IN')}`;$('header-pct').textContent=`${t.pct_complete}%`;$('header-bar').style.width=`${t.pct_complete}%`;$('closed-count').textContent=`${d.leads.closed_count||0} closed`;const dot=$('followup-dot');d.due_followups>0?dot.classList.remove('hidden'):dot.classList.add('hidden');
$('dash-stats-grid').innerHTML=[{l:'Today Hunted',v:d.today.leads_added,i:'fa-crosshairs',c:'text-brand-600',bg:'from-brand-50 to-blue-50'},{l:'Contacted',v:d.today.contacted,i:'fa-phone',c:'text-cyan-600',bg:'from-cyan-50 to-teal-50'},{l:'This Week',v:d.week.leads_added,i:'fa-chart-simple',c:'text-emerald-600',bg:'from-emerald-50 to-green-50'},{l:'Conversion',v:d.conversion_rate+'%',i:'fa-bolt',c:'text-amber-600',bg:'from-amber-50 to-orange-50'}].map((c,i)=>`<div class="stat-card p-3 sm:p-4 bg-gradient-to-br ${c.bg}" style="animation:stagger .4s cubic-bezier(.16,1,.3,1) both;animation-delay:${i*.06}s"><div class="flex items-center gap-1.5 sm:gap-2 mb-1.5 sm:mb-2"><div class="w-6 h-6 sm:w-7 sm:h-7 rounded-lg bg-white/80 flex items-center justify-center"><i class="fa-solid ${c.i} text-[9px] sm:text-[10px] ${c.c}"></i></div><span class="text-[7px] sm:text-[8px] text-ink-400 uppercase tracking-wider font-bold">${c.l}</span></div><p class="text-xl sm:text-2xl font-black ${c.c} font-display">${c.v}</p></div>`).join('');
const rv=await api('revenue.php');if(rv.goals?.length){const cols=['from-brand-50 to-blue-50 border-brand-100','from-cyan-50 to-teal-50 border-cyan-100','from-pink-50 to-rose-50 border-pink-100','from-amber-50 to-orange-50 border-amber-100','from-emerald-50 to-green-50 border-emerald-100'];const bars=['bg-brand-400','bg-cyan-400','bg-pink-400','bg-amber-400','bg-emerald-400'];$('dash-goals').innerHTML=rv.goals.map((g,i)=>{const x=(g.priority_order||i)%5;return`<div class="card-flat bg-gradient-to-br ${cols[x]} p-3 sm:p-4"><div class="flex items-center gap-2 mb-1.5 sm:mb-2"><span class="text-sm">${g.emoji}</span><span class="text-[10px] sm:text-[11px] font-semibold text-ink-700">${g.name}</span></div><p class="text-base sm:text-lg font-black font-display text-ink-900">${sym}${parseFloat(g.target_amount).toLocaleString('en-IN')}</p><div class="w-full h-1.5 bg-white/60 rounded-full overflow-hidden mt-2"><div class="h-full rounded-full ${bars[x]} progress-bar" style="width:${g.progress}%"></div></div><p class="text-[8px] text-ink-400 mt-1 font-mono">${g.progress}%</p></div>`;}).join('');}
const act=$('dash-activity');const ic={created:'fa-circle-plus text-brand-500',status_change:'fa-arrows-rotate text-violet-500',note_added:'fa-note-sticky text-amber-500',contacted:'fa-phone text-cyan-500',pitch_sent:'fa-paper-plane text-brand-500',payment_received:'fa-indian-rupee-sign text-emerald-500',settings_updated:'fa-gear text-ink-400',search_performed:'fa-magnifying-glass text-brand-500'};act.innerHTML=d.recent_activity?.length?d.recent_activity.map(a=>`<div class="flex items-center gap-2 sm:gap-3 py-1.5 sm:py-2 border-b border-ink-100 last:border-0"><div class="w-6 h-6 sm:w-7 sm:h-7 rounded-lg bg-ink-50 flex items-center justify-center flex-shrink-0"><i class="fa-solid ${ic[a.action_type]||'fa-circle text-ink-300'} text-[9px] sm:text-[10px]"></i></div><div class="flex-1 min-w-0"><p class="text-[10px] sm:text-[11px] text-ink-600 truncate">${rawText(a.description||a.action_type)}</p><p class="text-[8px] sm:text-[9px] text-ink-400">${a.business_name?rawText(a.business_name)+' · ':''}${timeAgo(a.created_at)}</p></div></div>`).join(''):'<p class="text-[11px] text-ink-400 text-center py-8"><i class="fa-solid fa-crosshairs mr-1"></i>No activity yet — start hunting!</p>';}
function timeAgo(d){const diff=Math.floor((new Date()-new Date(d))/1000);if(diff<60)return'just now';if(diff<3600)return`${Math.floor(diff/60)}m`;if(diff<86400)return`${Math.floor(diff/3600)}h`;return`${Math.floor(diff/86400)}d`;}

// ═══ HUNT — Updated for v3 monthly limits + active scores ═══
function initNicheChips(){$('niche-chips').innerHTML=APP.niches.map(n=>`<button onclick="setHuntNiche('${n.query}')" class="btn btn-ghost px-2.5 sm:px-3 py-1 sm:py-1.5 text-[9px] sm:text-[10px] font-medium"><i class="fa-solid ${n.icon} mr-1 text-ink-400"></i>${n.label}</button>`).join('');}
function setHuntNiche(q){$('hunt-niche').value=q;updateExternalLink();}
function updateExternalLink(){const n=$('hunt-niche').value||'business',c=$('hunt-city').value||'Pune',a=$('hunt-area').value||'';const el=$('open-maps-external');if(el)el.href=`https://www.google.com/maps/search/${encodeURIComponent(n+' '+(a?a+' ':'')+c)}`;}
['hunt-niche','hunt-city','hunt-area'].forEach(id=>$(id)?.addEventListener('input',updateExternalLink));
async function loadSearchLimits(){const d=await api('places.php?action=limits');if(d.remaining!==undefined){$('searches-remaining').textContent=d.remaining;$('searches-limit').textContent=d.month_limit||d.limit||10;}}
function searchMapsEmbed(){const n=$('hunt-niche').value||'business',c=$('hunt-city').value||'Pune',a=$('hunt-area').value||'';const q=encodeURIComponent(`${n} ${a?a+' ':''}${c}`);$('map-iframe').src=`https://www.google.com/maps/embed/v1/search?key=YOUR_GOOGLE_MAPS_EMBED_KEY&q=${q}`;$('map-iframe').classList.remove('hidden');$('map-placeholder').classList.add('hidden');$('qa-area').value=a||c;updateExternalLink();}
function toggleNoWebsite(){const t=$('no-website-toggle');t.classList.toggle('active');APP.noWebsiteFilter=t.classList.contains('active');}
async function huntSearch(){const n=$('hunt-niche').value,c=$('hunt-city').value||'Pune',a=$('hunt-area').value||'';if(!n){showToast('Enter a niche first','warning');return;}if(!APP.noWebsiteFilter){searchMapsEmbed();showToast('Map loaded — toggle filter ON to search API','info');return;}const btn=$('hunt-search-btn');btn.innerHTML='<div class="spinner"></div> Searching...';btn.disabled=true;const params=new URLSearchParams({niche:n,city:c,area:a,no_website:'1'});const d=await api(`places.php?${params}`);btn.innerHTML='<i class="fa-solid fa-magnifying-glass"></i> Search Leads';btn.disabled=false;if(d.error){if(d.limit){showToast(d.upgrade_msg||'Limit reached!','warning');if(d.show_packs)showPricingFromApp();return;}showToast(d.error,'error');return;}if(d.searches_remaining!==undefined){$('searches-remaining').textContent=d.searches_remaining;}APP.searchResults=d.results||[];searchMapsEmbed();const ct=$('hunt-results');if(!d.results?.length){ct.innerHTML=`<div class="card p-6 sm:p-8 text-center"><i class="fa-solid fa-magnifying-glass text-3xl text-ink-200 mb-3"></i><p class="text-xs text-ink-500">${d.no_cache?'No cached data for this search. Upgrade to Pro for live results.':'No results. Try a different niche or area.'}</p>${d.from_cache?'<p class="text-[9px] text-ink-400 mt-1"><i class="fa-solid fa-database mr-1"></i>Cached results</p>':''}</div>`;ct.classList.remove('hidden');return;}const wa=APP.settings.whatsapp_country_code||'91';ct.innerHTML=`<div class="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-2 gap-1"><p class="text-[9px] sm:text-[10px] text-ink-400 uppercase tracking-[0.15em] font-bold">${d.results.length} businesses found</p><div class="flex items-center gap-2"><span class="text-[8px] sm:text-[9px] text-ink-400">${d.total_found} total</span>${d.from_cache?'<span class="px-1.5 py-0.5 rounded text-[7px] font-bold bg-amber-50 text-amber-600 border border-amber-100"><i class="fa-solid fa-database mr-0.5"></i>Cached</span>':'<span class="px-1.5 py-0.5 rounded text-[7px] font-bold bg-emerald-50 text-emerald-600 border border-emerald-100"><i class="fa-solid fa-bolt mr-0.5"></i>Live</span>'}</div></div><button onclick="addAllFromSearch()" class="btn btn-success w-full py-2 sm:py-2.5 text-xs font-bold mb-2 sm:mb-3"><i class="fa-solid fa-plus mr-1"></i>Add All ${d.results.length} to Pipeline</button>`+d.results.map((r,i)=>{const ph=r.phone?r.phone.replace(/\D/g,''):'';const name=rawText(r.name);const scoreBadge=r.active_score!==undefined?activeScoreBadge(r.active_score,r.active_label||'cold'):'';return`<div class="card p-2.5 sm:p-4 group" style="animation:stagger .35s cubic-bezier(.16,1,.3,1) both;animation-delay:${Math.min(i*.04,.4)}s"><div class="flex flex-col sm:flex-row sm:items-center justify-between gap-2"><div class="flex-1 min-w-0"><div class="flex items-center gap-1.5 sm:gap-2 flex-wrap"><h4 class="font-bold text-xs sm:text-sm text-ink-900 truncate max-w-[180px] sm:max-w-none">${esc(name)}</h4>${scoreBadge}${r.has_website===false?'<span class="px-1.5 py-0.5 rounded-md text-[7px] sm:text-[8px] font-bold bg-emerald-50 text-emerald-700 border border-emerald-100"><i class="fa-solid fa-circle-xmark mr-0.5"></i>No Site</span>':''}${r.rating?`<span class="text-[8px] sm:text-[9px] text-amber-600 font-semibold"><i class="fa-solid fa-star text-[7px] sm:text-[8px]"></i> ${r.rating}</span>`:''}</div><p class="text-[9px] sm:text-[10px] text-ink-400 mt-0.5 truncate">${esc(r.address)}</p>${ph?`<p class="text-[9px] sm:text-[10px] text-ink-500 font-mono mt-0.5">${ph}</p>`:''}</div><div class="flex items-center gap-1 sm:gap-1.5 flex-shrink-0"><button onclick="addFromSearch(${i})" class="btn px-2 sm:px-3 py-1 sm:py-1.5 text-[9px] sm:text-[10px] font-bold bg-brand-50 text-brand-700 border border-brand-100 hover:bg-brand-100"><i class="fa-solid fa-plus mr-0.5"></i><span class="hidden sm:inline">Pipeline</span><span class="sm:hidden">Add</span></button><button onclick="copyInfoForAI(${i})" class="btn px-2 sm:px-3 py-1 sm:py-1.5 text-[9px] sm:text-[10px] font-bold bg-amber-50 text-amber-700 border border-amber-100 hover:bg-amber-100" title="Copy for AI"><i class="fa-regular fa-copy"></i></button>${ph?`<a href="https://wa.me/${wa}${ph}" target="_blank" rel="noopener" class="btn px-2 sm:px-2.5 py-1 sm:py-1.5 text-[9px] sm:text-[10px] font-bold bg-emerald-50 text-emerald-700 border border-emerald-100 hover:bg-emerald-100"><i class="fa-brands fa-whatsapp"></i></a>`:''}</div></div></div>`;}).join('');ct.classList.remove('hidden');}
async function addAllFromSearch(){let added=0;for(const r of APP.searchResults){if(!r)continue;const res=await api('leads.php','POST',{business_name:r.name,phone:r.phone||'',niche:$('hunt-niche').value||'other',city:$('hunt-city').value||'',area:$('hunt-area').value||'',source:'google_maps',website_url:r.website_url||'',has_website:r.has_website?1:0,google_rating:r.rating||null});if(res.success)added++;}showToast(`${added} leads added!`,'success');}
async function addFromSearch(idx){const r=APP.searchResults[idx];if(!r)return;const res=await api('leads.php','POST',{business_name:r.name,phone:r.phone||'',niche:$('hunt-niche').value||'other',city:$('hunt-city').value||'',area:$('hunt-area').value||'',source:'google_maps',website_url:r.website_url||'',has_website:r.has_website?1:0,google_rating:r.rating||null});if(res.success)showToast(`${rawText(r.name)} added!`,'success');else if(res.duplicate)showToast('Already in pipeline','warning');else if(res.upgrade)showToast('Lead limit reached','warning');}
function copyInfoForAI(idx){const r=APP.searchResults[idx];if(!r)return;const info=`Business: ${r.name}\nAddress: ${r.address}\nPhone: ${r.phone||'N/A'}\nRating: ${r.rating||'N/A'} (${r.user_ratings_total||0} reviews)\nHas Website: ${r.has_website?'Yes':'No'}\nActive Score: ${r.active_score||'N/A'} (${r.active_label||'unknown'})\nNiche: ${$('hunt-niche').value}\nCity: ${$('hunt-city').value}\n\nCreate a professional demo website for this business.`;navigator.clipboard.writeText(info).then(()=>showToast('Copied for AI!','info'));}
async function quickAddLead(){const b=$('qa-business').value;if(!b.trim()){showToast('Business name required','warning');return;}const res=await api('leads.php','POST',{business_name:b,phone:$('qa-phone').value||'',niche:$('hunt-niche').value||'other',city:$('hunt-city').value||'',area:$('qa-area').value||'',source:'google_maps'});if(res.success){$('qa-business').value='';$('qa-phone').value='';showToast('Lead added!','success');}else if(res.upgrade)showToast('Lead limit reached','warning');}

// ═══ PIPELINE ═══
const ST={new:{l:'New',b:'badge-new',i:'fa-circle-dot'},contacted:{l:'Contacted',b:'badge-contacted',i:'fa-phone'},followup:{l:'Follow-up',b:'badge-followup',i:'fa-clock'},negotiating:{l:'Negotiating',b:'badge-negotiating',i:'fa-handshake'},closed:{l:'Closed',b:'badge-closed',i:'fa-circle-check'},lost:{l:'Lost',b:'badge-lost',i:'fa-circle-xmark'}};
async function loadLeads(){const status=$('filter-status')?.value||'all',search=$('search-leads')?.value||'';const d=await api(`leads.php?status=${status}&search=${encodeURIComponent(search)}`);if(d.error){$('leads-list').innerHTML=`<div class="text-center py-16 sm:py-20"><i class="fa-solid fa-triangle-exclamation text-3xl sm:text-4xl text-ink-200 mb-3"></i><p class="text-[10px] sm:text-[11px] text-ink-400">Database not connected. Run gigbase_v3.sql first.</p></div>`;return;}const{leads,stats}=d,wa=APP.settings.whatsapp_country_code||'91';$('pipeline-stats').innerHTML=[{l:'Total',v:stats?.total||0,c:'text-ink-900',bg:'from-white to-ink-50',i:'fa-layer-group'},{l:'New',v:stats?.new_count||0,c:'text-brand-600',bg:'from-brand-50 to-blue-50',i:'fa-circle-dot'},{l:'Contacted',v:stats?.contacted_count||0,c:'text-amber-600',bg:'from-amber-50 to-orange-50',i:'fa-phone'},{l:'Negotiating',v:stats?.negotiating_count||0,c:'text-violet-600',bg:'from-violet-50 to-purple-50',i:'fa-handshake'},{l:'Closed',v:stats?.closed_count||0,c:'text-emerald-600',bg:'from-emerald-50 to-green-50',i:'fa-circle-check'},{l:'Lost',v:stats?.lost_count||0,c:'text-red-400',bg:'from-red-50 to-rose-50',i:'fa-circle-xmark'}].map(s=>`<div class="stat-card p-2 sm:p-3 text-center bg-gradient-to-br ${s.bg}"><div class="w-5 h-5 sm:w-6 sm:h-6 rounded-lg bg-white/80 flex items-center justify-center mx-auto mb-0.5 sm:mb-1"><i class="fa-solid ${s.i} text-[8px] sm:text-[9px] ${s.c}"></i></div><p class="text-sm sm:text-lg font-black ${s.c} font-display">${s.v}</p><p class="text-[6px] sm:text-[7px] text-ink-400 uppercase tracking-wider mt-0.5 font-bold">${s.l}</p></div>`).join('');if(!leads?.length){$('leads-list').innerHTML=`<div class="text-center py-16 sm:py-20"><i class="fa-solid fa-crosshairs text-3xl sm:text-4xl text-ink-200 mb-3"></i><p class="text-[10px] sm:text-[11px] text-ink-400">No leads yet. Go hunt!</p></div>`;return;}$('leads-list').innerHTML=leads.map((l,i)=>{const sc=ST[l.status]||ST.new;const ni=APP.niches.find(n=>n.id===l.niche||n.query===l.niche);const ph=l.phone?l.phone.replace(/\D/g,''):'';const name=rawText(l.business_name);const scoreBadge=l.active_score?activeScoreBadge(l.active_score,l.active_label||'cold'):'';return`<div class="card p-2.5 sm:p-4 group" style="animation:stagger .35s cubic-bezier(.16,1,.3,1) both;animation-delay:${Math.min(i*.03,.3)}s"><div class="flex flex-col sm:flex-row sm:items-center justify-between gap-1.5 sm:gap-2"><div class="flex-1 min-w-0"><div class="flex items-center gap-1.5 sm:gap-2 flex-wrap"><div class="w-5 h-5 sm:w-6 sm:h-6 rounded-lg bg-ink-50 flex items-center justify-center flex-shrink-0"><i class="fa-solid ${ni?.icon||'fa-building'} text-[9px] sm:text-[10px] text-ink-400"></i></div><h4 class="font-bold text-xs sm:text-sm text-ink-900 truncate max-w-[150px] sm:max-w-none">${esc(name)}</h4><span class="px-1 sm:px-1.5 py-0.5 rounded-md text-[7px] sm:text-[8px] font-bold ${sc.b}"><i class="fa-solid ${sc.i} mr-0.5 text-[6px] sm:text-[7px]"></i>${sc.l}</span>${scoreBadge}${l.priority>0?'<i class="fa-solid fa-star text-[8px] sm:text-[9px] text-amber-500"></i>':''}</div><div class="flex items-center gap-1.5 sm:gap-2.5 mt-0.5 flex-wrap text-[9px] sm:text-[10px] text-ink-400">${l.owner_name?`<span>${rawText(l.owner_name)}</span>`:''} ${ph?`<span class="font-mono">${ph}</span>`:''} ${l.city?`<span><i class="fa-solid fa-location-dot mr-0.5"></i>${l.area?rawText(l.area)+', ':''}${rawText(l.city)}</span>`:''}</div>${l.notes?`<p class="text-[9px] sm:text-[10px] text-ink-400 mt-1 truncate italic"><i class="fa-solid fa-note-sticky mr-1"></i>${rawText(l.notes)}</p>`:''}</div><div class="flex items-center gap-1 sm:gap-1.5 flex-shrink-0"><select onchange="updateLeadStatus(${l.id},this.value)" class="px-1 sm:px-1.5 py-0.5 sm:py-1 text-[8px] sm:text-[9px] rounded-lg">${Object.entries(ST).map(([k,v])=>`<option value="${k}" ${l.status===k?'selected':''}>${v.l}</option>`).join('')}</select>${ph?`<a href="https://wa.me/${wa}${ph}" target="_blank" rel="noopener" class="btn px-1.5 sm:px-2 py-0.5 sm:py-1 text-[9px] sm:text-[10px] font-bold bg-emerald-50 text-emerald-700 border border-emerald-100"><i class="fa-brands fa-whatsapp"></i></a>`:''}<button onclick="promptNote(${l.id})" class="btn px-1.5 sm:px-2 py-0.5 sm:py-1 text-[9px] sm:text-[10px] bg-ink-50 text-ink-500 border border-ink-200"><i class="fa-solid fa-note-sticky"></i></button><button onclick="deleteLead(${l.id})" class="btn px-1.5 sm:px-2 py-0.5 sm:py-1 text-[9px] sm:text-[10px] text-red-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"><i class="fa-solid fa-trash"></i></button></div></div></div>`;}).join('');}
function toggleLeadForm(){$('lead-form').classList.toggle('hidden');}
async function createLead(){const d={business_name:$('f-business').value,owner_name:$('f-owner').value,phone:$('f-phone').value,email:$('f-email').value,niche:$('f-niche').value,city:$('f-city').value,area:$('f-area').value,budget:$('f-budget').value,instagram:$('f-instagram').value,source:$('f-source').value,notes:$('f-notes').value};if(!d.business_name.trim()){showToast('Name required','warning');return;}const r=await api('leads.php','POST',d);if(r.success){['f-business','f-owner','f-phone','f-email','f-niche','f-area','f-budget','f-instagram','f-notes'].forEach(id=>$(id).value='');$('lead-form').classList.add('hidden');loadLeads();showToast('Lead added!','success');}else if(r.upgrade)showToast('Lead limit reached','warning');}
async function updateLeadStatus(id,s){await api('leads.php','PUT',{id,status:s});loadLeads();}
async function promptNote(id){const n=prompt('Add note:');if(n!==null){await api('leads.php','PUT',{id,notes:n});loadLeads();}}
async function deleteLead(id){if(!confirm('Delete this lead?'))return;await api('leads.php','DELETE',{id});loadLeads();}
function exportLeads(){window.open('api/leads.php?action=export','_blank');}

// ═══ PITCH ═══
async function loadPitchTemplates(){const d=await api('pitches.php');if(d.templates){APP.pitchTemplates=d.templates;const ic={whatsapp:'fa-brands fa-whatsapp',email:'fa-solid fa-envelope',dm:'fa-solid fa-globe',cold_call:'fa-solid fa-phone',custom:'fa-solid fa-pen'};$('pitch-templates').innerHTML=d.templates.map(t=>`<button onclick="selectPitchTemplate(${t.id})" data-pitch="${t.id}" class="pitch-btn p-2.5 sm:p-3 rounded-xl border text-center transition-all card cursor-pointer"><i class="${ic[t.category]||'fa-solid fa-paper-plane'} text-base sm:text-lg block text-ink-400"></i><span class="text-[8px] sm:text-[9px] text-ink-500 block mt-1 sm:mt-1.5">${esc(t.name)}</span></button>`).join('');}}
async function selectPitchTemplate(id){APP.selectedPitchTemplate=id;document.querySelectorAll('.pitch-btn').forEach(b=>{b.classList.remove('bg-brand-50','border-brand-200');});const btn=document.querySelector(`[data-pitch="${id}"]`);if(btn)btn.classList.add('bg-brand-50','border-brand-200');generatePitch();}
async function generatePitch(){if(!APP.selectedPitchTemplate)return;const d=await api('pitches.php','POST',{template_id:APP.selectedPitchTemplate,business_name:$('p-business').value||'[Business]',owner_name:$('p-owner').value||'[Owner]',niche:$('p-niche').value||'niche'});if(d.generated)$('pitch-output').textContent=d.generated;}
['p-business','p-owner','p-niche'].forEach(id=>$(id)?.addEventListener('input',debounce(()=>{if(APP.selectedPitchTemplate)generatePitch();},400)));
function copyPitch(){const t=$('pitch-output').textContent;navigator.clipboard.writeText(t).then(()=>{const b=$('copy-pitch-btn');b.innerHTML='<i class="fa-solid fa-check mr-1"></i>Copied!';b.classList.add('bg-emerald-50','text-emerald-700','border-emerald-200');setTimeout(()=>{b.innerHTML='<i class="fa-regular fa-copy mr-1"></i>Copy';b.classList.remove('bg-emerald-50','text-emerald-700','border-emerald-200');},2000);});}

// ═══ REVENUE ═══
async function loadRevenue(){const d=await api('revenue.php');if(d.error)return;const{entries,stats,goals,target,monthly}=d,s=APP.settings,sym=SYM[s.currency]||'₹';const tc=parseFloat(stats?.total_combined||0),pct=Math.min(100,(tc/Math.max(1,target))*100);$('total-revenue').textContent=`${sym}${tc.toLocaleString('en-IN')}`;$('rev-target-label').textContent=`Target: ${sym}${target.toLocaleString('en-IN')}`;$('remaining-amount').textContent=`${sym}${Math.max(0,target-tc).toLocaleString('en-IN')} to go`;$('revenue-bar').style.width=`${pct.toFixed(1)}%`;$('revenue-pct').textContent=`${pct.toFixed(1)}%`;const ml=Math.max(1,Math.ceil((new Date(s.target_deadline||'2027-05-01')-new Date())/(1e3*60*60*24*30)));$('monthly-needed').textContent=`${sym}${Math.ceil(Math.max(0,target-tc)/ml).toLocaleString('en-IN')}/mo needed`;if(parseFloat(stats?.total_usd||0)>0){$('usd-note').textContent=`Incl. $${parseFloat(stats.total_usd).toLocaleString()} USD`;$('usd-note').classList.remove('hidden');}if(goals?.length){const cols=['from-brand-50 to-blue-50 border-brand-100','from-cyan-50 to-teal-50 border-cyan-100','from-pink-50 to-rose-50 border-pink-100','from-amber-50 to-orange-50 border-amber-100','from-emerald-50 to-green-50 border-emerald-100'];const bars=['bg-brand-400','bg-cyan-400','bg-pink-400','bg-amber-400','bg-emerald-400'];$('revenue-goals').innerHTML=goals.map((g,i)=>`<div class="card-flat bg-gradient-to-br ${cols[i%5]} p-3 sm:p-4"><div class="flex items-center gap-2 mb-1.5 sm:mb-2"><span class="text-sm">${g.emoji}</span><span class="text-[10px] sm:text-[11px] font-semibold text-ink-700">${g.name}</span></div><p class="text-base sm:text-lg font-black font-display text-ink-900">${sym}${parseFloat(g.target_amount).toLocaleString('en-IN')}</p><div class="w-full h-1.5 bg-white/60 rounded-full overflow-hidden mt-2"><div class="h-full rounded-full ${bars[i%5]} progress-bar" style="width:${g.progress}%"></div></div><p class="text-[8px] text-ink-400 mt-1 font-mono">${g.progress}%</p></div>`).join('');}if(monthly?.length){const mx=Math.max(...monthly.map(m=>parseFloat(m.total)));$('revenue-chart').innerHTML=`<h3 class="text-[10px] font-bold text-ink-400 uppercase tracking-[0.15em] mb-3 sm:mb-4"><i class="fa-solid fa-chart-bar mr-1"></i>Monthly Revenue</h3><div class="flex items-end gap-1 sm:gap-1.5 h-28 sm:h-36">${monthly.map(m=>{const v=parseFloat(m.total),h=mx>0?Math.max(6,(v/mx)*100):6;const ml2=new Date(m.month+'-01').toLocaleDateString('en-US',{month:'short'});return`<div class="flex-1 flex flex-col items-center gap-1 sm:gap-1.5 group"><span class="text-[7px] sm:text-[8px] text-ink-400 font-mono opacity-0 group-hover:opacity-100 transition-opacity">${sym}${v.toLocaleString('en-IN')}</span><div class="w-full rounded-t-lg bg-gradient-to-t from-amber-400 to-amber-200 cursor-pointer hover:from-amber-500 transition-colors" style="height:${h}%"></div><span class="text-[7px] sm:text-[8px] text-ink-400">${ml2}</span></div>`;}).join('')}</div>`;}if(entries?.length){$('revenue-list').innerHTML=`<h3 class="text-[10px] font-bold text-ink-400 uppercase tracking-[0.15em] mb-2"><i class="fa-solid fa-receipt mr-1"></i>Payments</h3>`+entries.map(e=>`<div class="flex items-center justify-between card px-2.5 sm:px-3 py-2 sm:py-2.5 group"><div class="min-w-0 flex-1"><p class="text-[10px] sm:text-[11px] font-medium text-ink-800 truncate">${rawText(e.client_name)}</p><p class="text-[8px] sm:text-[9px] text-ink-400">${new Date(e.payment_date).toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})}${e.payment_method?' · '+rawText(e.payment_method):''}</p></div><div class="flex items-center gap-1.5 sm:gap-2 flex-shrink-0"><p class="text-[10px] sm:text-[11px] font-bold text-emerald-600 font-mono">${SYM[e.currency]||'₹'}${parseFloat(e.amount).toLocaleString()}</p><button onclick="deleteRevenue(${e.id})" class="text-red-300 hover:text-red-500 text-[9px] sm:text-[10px] opacity-0 group-hover:opacity-100 transition-opacity"><i class="fa-solid fa-trash"></i></button></div></div>`).join('');}}
function toggleRevenueForm(){const f=$('revenue-form');f.classList.toggle('hidden');if(!f.classList.contains('hidden')){$('r-date').value=new Date().toISOString().slice(0,10);$('r-currency').value=APP.settings.currency||'INR';}}
async function addRevenue(){const d={client_name:$('r-client').value,amount:$('r-amount').value,payment_date:$('r-date').value,currency:$('r-currency').value,payment_method:$('r-method').value,notes:$('r-notes').value};if(!d.client_name||!d.amount){showToast('Client & amount required','warning');return;}const r=await api('revenue.php','POST',d);if(r.success){['r-client','r-amount','r-method','r-notes'].forEach(id=>$(id).value='');$('revenue-form').classList.add('hidden');loadRevenue();showToast('Payment recorded!','success');}}
async function deleteRevenue(id){if(!confirm('Delete?'))return;await api('revenue.php','DELETE',{id});loadRevenue();}

// ═══ PORTFOLIO ═══
async function loadPortfolio(){const d=await api('portfolio.php');const projects=d.projects||[];const limits=APP.settings.search_limits||{portfolio_slots:2};$('portfolio-count').textContent=`${projects.length} / ${limits.portfolio_slots||2} slots`;if(!projects.length){$('portfolio-grid').innerHTML=`<div class="card p-8 sm:p-10 text-center col-span-full"><i class="fa-solid fa-images text-3xl text-ink-200 mb-3"></i><p class="text-xs text-ink-400">No projects yet. Add your first work above!</p></div>`;return;}$('portfolio-grid').innerHTML=projects.map((p,i)=>`<div class="card overflow-hidden group" style="animation:stagger .4s cubic-bezier(.16,1,.3,1) both;animation-delay:${i*.06}s">${p.image_path?`<div class="h-32 sm:h-40 bg-ink-100 overflow-hidden"><img src="${p.image_path}" alt="${esc(p.title)}" class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" loading="lazy"></div>`:'<div class="h-32 sm:h-40 bg-gradient-to-br from-brand-50 to-cyan-50 flex items-center justify-center"><i class="fa-solid fa-images text-3xl sm:text-4xl text-ink-200"></i></div>'}<div class="p-3 sm:p-4"><h4 class="text-xs sm:text-sm font-bold text-ink-900 truncate">${esc(p.title)}</h4>${p.client_name?`<p class="text-[9px] sm:text-[10px] text-ink-400 mt-0.5"><i class="fa-solid fa-user mr-1"></i>${esc(p.client_name)}</p>`:''} ${p.tech_stack?`<p class="text-[8px] sm:text-[9px] text-brand-600 font-mono mt-1">${esc(p.tech_stack)}</p>`:''} ${p.description?`<p class="text-[9px] sm:text-[10px] text-ink-500 mt-1.5 line-clamp-2">${esc(p.description)}</p>`:''}<div class="flex items-center justify-between mt-2 sm:mt-3">${p.url?`<a href="${esc(p.url)}" target="_blank" rel="noopener" class="text-[9px] sm:text-[10px] text-brand-600 font-semibold hover:text-brand-500"><i class="fa-solid fa-arrow-up-right-from-square mr-1"></i>View</a>`:'<span></span>'}<button onclick="deleteProject(${p.id})" class="text-[9px] sm:text-[10px] text-red-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"><i class="fa-solid fa-trash mr-1"></i>Delete</button></div></div></div>`).join('');}
async function uploadProject(){const title=$('pf-title').value;if(!title){showToast('Project title required','warning');return;}const fd=new FormData();fd.append('title',title);fd.append('url',$('pf-url').value);fd.append('client_name',$('pf-client').value);fd.append('tech_stack',$('pf-tech').value);fd.append('description',$('pf-desc').value);const img=$('pf-image');if(img.files[0])fd.append('image',img.files[0]);try{const r=await fetch('api/portfolio.php',{method:'POST',body:fd});const d=await r.json();if(d.success){['pf-title','pf-url','pf-client','pf-tech','pf-desc'].forEach(id=>$(id).value='');$('pf-image').value='';$('pf-file-label').textContent='Upload Screenshot';loadPortfolio();showToast('Project added!','success');}else showToast(d.error||'Failed','error');}catch(e){showToast('Upload failed','error');}}
async function deleteProject(id){if(!confirm('Delete this project?'))return;await api('portfolio.php','DELETE',{id});loadPortfolio();}

// ═══ PLAYBOOK ═══
function loadPlaybook(){const s=APP.settings,sym=SYM[s.currency]||'₹',target=parseFloat(s.revenue_target||550000),ml=Math.max(1,Math.ceil((new Date(s.target_deadline||'2027-05-01')-new Date())/(1e3*60*60*24*30))),mn=Math.ceil(target/ml),ad=parseFloat(s.avg_deal_size_inr||15000),cp=Math.ceil(mn/ad),au=parseFloat(s.avg_deal_size_usd||350),rt=parseFloat(s.usd_to_inr_rate||85),uc=Math.ceil(mn/(au*rt));const tl=target>=100000?`${sym}${(target/100000).toFixed(1)}L`:`${sym}${target.toLocaleString('en-IN')}`;$('playbook-math-title').innerHTML=`<i class="fa-solid fa-calculator text-brand-600 mr-2"></i>The Math — ${tl} Blueprint`;$('playbook-math').innerHTML=[{v:`${sym}${mn.toLocaleString('en-IN')}`,l:'Per month needed',i:'fa-chart-line',c:'text-brand-600'},{v:`${cp}`,l:`Clients/mo at ${sym}${ad.toLocaleString('en-IN')}`,i:'fa-flag',c:'text-emerald-600'},{v:`${uc}`,l:`Intl at $${au}`,i:'fa-globe',c:'text-cyan-600'}].map(c=>`<div class="stat-card p-4 sm:p-5 text-center bg-gradient-to-br from-white to-ink-50"><div class="w-7 h-7 sm:w-8 sm:h-8 rounded-lg bg-white/80 flex items-center justify-center mx-auto mb-1.5 sm:mb-2"><i class="fa-solid ${c.i} ${c.c}"></i></div><p class="text-xl sm:text-2xl font-black font-display text-ink-900">${c.v}</p><p class="text-[8px] sm:text-[9px] text-ink-400 mt-1 sm:mt-1.5">${c.l}</p></div>`).join('');}

// ═══ TOAST ═══
function showToast(msg,type='info'){const icons={success:'fa-circle-check',error:'fa-circle-exclamation',warning:'fa-triangle-exclamation',info:'fa-circle-info'};const t=document.createElement('div');t.className=`toast toast-${type}`;t.innerHTML=`<i class="fa-solid ${icons[type]||icons.info}"></i><span>${msg}</span>`;document.body.appendChild(t);setTimeout(()=>{t.classList.add('toast-exit');setTimeout(()=>t.remove(),300);},3000);}
</script>
</body>
</html>